namespace Pkcs12Tool.Controllers;

[ApiController]
[Route("api/v{version:apiVersion}/pkcs12")]
public class Pkcs12Controller : ControllerBase
{
    private readonly ILogger<Pkcs12Controller> _logger;

    public Pkcs12Controller(ILogger<Pkcs12Controller> logger)
    {
        _logger = logger;
    }

    [HttpPost("import")]
    [ProducesResponseType(typeof(ImportResult), StatusCodes.Status200OK)]
    public async Task<ActionResult<ImportResult>> ImportPkcs12([FromForm] IFormFile pkcs12File)
    {
        if (pkcs12File == null || pkcs12File.Length <= 0)
            return BadRequest("No file was uploaded");

        var importResult = new ImportResult();

        try
        {
            using var stream = pkcs12File.OpenReadStream();
            using var reader = new PemReader(new StreamReader(stream));
            var pkcs12Content = (Pkcs12BagAttributeCertificate)reader.ReadObject();

            importResult.Certificates = new List<X509Certificate2>();
            foreach (var bag in pkcs12Content.GetBags())
            {
                if (bag is X509CertificateBag x509Bag)
                {
                    var cert = new X509Certificate2(x509Bag.Certificate);
                    importResult.Certificates.Add(cert);
                }
            }
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Failed to import PKCS#12 file");
            return BadRequest("Failed to import PKCS#12 file");
        }

        return Ok(importResult);
    }

    [HttpPost("export")]
    [ProducesResponseType(typeof(ExportResult), StatusCodes.Status200OK)]
    public async Task<ActionResult<ExportResult>> ExportPkcs12([FromForm] IFormFile pemFile)
    {
        if (pemFile == null || pemFile.Length <= 0)
            return BadRequest("No file was uploaded");

        var exportResult = new ExportResult();

        try
        {
            using var stream = pemFile.OpenReadStream();
            using var reader = new PemReader(new StreamReader(stream));
            var cert = (X509Certificate)reader.ReadObject();

            var keyPair = new AsymmetricCipherKeyPair(cert.GetPublicKey(), cert.GetPrivateKey());
            var pkcs12BagAttrCert = new Pkcs12BagAttributeCertificate(keyPair, new X509Certificate[] { cert });

            using var memoryStream = new MemoryStream();
            var writer = new PemWriter(new StreamWriter(memoryStream));
            writer.WriteObject(pkcs12BagAttrCert);
            writer.Writer.Flush();

            exportResult.Pkcs12Content = Encoding.UTF8.GetString(memoryStream.ToArray());
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Failed to export PKCS#12 file");
            return BadRequest("Failed to export PKCS#12 file");
        }

        return Ok(exportResult);
    }
}